  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_itinerary_sequence` (`itinerary_id`,`sequence_number`),
  KEY `fk_itinerary_items_place` (`place_id`),
  KEY `idx_itinerary_items_itinerary_id` (`itinerary_id`),
  CONSTRAINT `fk_itinerary_items_itinerary` FOREIGN KEY (`itinerary_id`) REFERENCES `itineraries` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_itinerary_items_place` FOREIGN KEY (`place_id`) REFERENCES `places` (`id`) ON DELETE SET NULL,
  CONSTRAINT `chk_item_status` CHECK ((`status` in (_utf8mb4'planned',_utf8mb4'completed',_utf8mb4'skipped'))),
  CONSTRAINT `chk_item_type` CHECK ((`item_type` in (_utf8mb4'hotel',_utf8mb4'restaurant',_utf8mb4'attraction',_utf8mb4'transport')))
