INSERT INTO `itinerary_items` VALUES (1,1,49,'hotel','Kunhar Sarai Hotel Balakot','Start the day with a relaxing morning at Kunhar Sarai Hotel Balakot. Take in the beautiful mountain views and enjoy the hotel\'s amenities. Be sure to check out by 10:00 AM to make the most of your day.','08:00:00','10:00:00',1,14660,34.5170537,73.3477612,'planned','2026-04-25 03:05:56'),(2,1,NULL,'transport','Local Transport','Travel to Al Kuresh using local transport. The journey should take around 30 minutes and cost approximately 2000 PKR.','10:00:00','10:30:00',2,2000,NULL,NULL,'planned','2026-04-25 03:05:56'),(3,1,48,'restaurant','Al Kuresh','Have lunch at Al Kuresh, a local restaurant serving delicious food. Be sure to try some of the regional specialties and enjoy the mountain views. Lunch should take around 2 hours.','11:00:00','13:00:00',3,1721,34.5500458,73.3538511,'planned','2026-04-25 03:05:56'),(4,2,51,'hotel','Check-in at Country Club Resort','Begin the day by checking into the Country Club Resort. Spend some time freshening up and getting ready for the day ahead. The resort offers a serene atmosphere, perfect for a mountain getaway. Estimated cost is 5734 PKR.','08:00:00','09:00:00',1,5734,34.5417998,73.3504933,'planned','2026-04-25 03:09:47'),(5,2,NULL,'transport','Local Travel','Travel to Al Kuresh restaurant for lunch. The journey will take around 30 minutes to an hour, depending on traffic. Enjoy the scenic views of the valley during the trip. Estimated cost for local travel is 2000 PKR.','09:00:00','10:00:00',2,2000,NULL,NULL,'planned','2026-04-25 03:09:47'),(6,2,48,'restaurant','Lunch at Al Kuresh','Have lunch at Al Kuresh, a local restaurant serving a variety of dishes. Spend around an hour enjoying the meal and taking in the surroundings. The estimated cost for lunch is 1721 PKR.','10:00:00','11:00:00',3,1721,34.5500458,73.3538511,'planned','2026-04-25 03:09:47');
/*!40000 ALTER TABLE `itinerary_items` ENABLE KEYS */;
UNLOCK TABLES;

