CREATE TABLE `places` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `destination_id` bigint NOT NULL,
  `source_place` varchar(150) DEFAULT NULL,
  `name` varchar(200) NOT NULL,
  `category` varchar(150) NOT NULL,
  `main_type` varchar(50) NOT NULL,
  `sub_type` varchar(100) DEFAULT NULL,
  `description` text,
  `latitude` decimal(10,7) NOT NULL,
  `longitude` decimal(10,7) NOT NULL,
  `raw_category` text,
  `cost_pkr` int DEFAULT NULL,
  `rating` decimal(2,1) DEFAULT NULL,
  `price_level` int DEFAULT NULL,
  `contact_number` varchar(50) DEFAULT NULL,
  `website_url` text,
  `address` text,
  `source` varchar(50) DEFAULT 'geoapify',
  `is_active` tinyint(1) DEFAULT '1',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_places_destination_id` (`destination_id`),
  KEY `idx_places_main_type` (`main_type`),
  KEY `idx_places_category` (`category`),
  CONSTRAINT `fk_places_destination` FOREIGN KEY (`destination_id`) REFERENCES `destinations` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chk_places_cost` CHECK ((`cost_pkr` >= 0)),
  CONSTRAINT `chk_places_main_type` CHECK ((`main_type` in (_utf8mb4'hotel',_utf8mb4'restaurant',_utf8mb4'attraction'))),
  CONSTRAINT `chk_places_price_level` CHECK ((`price_level` between 1 and 5)),
  CONSTRAINT `chk_places_rating` CHECK ((`rating` between 0 and 5))
) ENGINE=InnoDB AUTO_INCREMENT=855 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
